const shuffle=a=>{const b=[...a];for(let i=b.length-1;i>0;i--){const j=Math.floor(Math.random()*(i+1));[b[i],b[j]]=[b[j],b[i]];}return b;};
const isActive=(r,ov)=>{if(ov&&ov[r.id]!==undefined)return ov[r.id];const n=new Date();return n>=new Date(r.start)&&n<=new Date(r.end+"T23:59:59");};
const bestAtt=atts=>{if(!atts||!atts.length)return null;return atts.reduce((b,a)=>(!b||a.total>b.total)?a:b,null);};
const brainType=t=>{if(t>=1200)return{icon:"🏆",name:"Brain Athlete",desc:"สมองฟิตสุดๆ ทุกด้านยอดเยี่ยม!",color:"#ffd700"};if(t>=900)return{icon:"💪",name:"Brain Warrior",desc:"แข็งแกร่งดี มีจุดแข็งชัดเจน",color:C.success};if(t>=600)return{icon:"🌱",name:"Brain Grower",desc:"กำลังเติบโต มีศักยภาพรอพัฒนา",color:C.warning};return{icon:"🔋",name:"Brain Charger",desc:"ถึงเวลาชาร์จสมอง!",color:C.magenta};};
